abstract class DifferentTouchInput
{
	public static DifferentTouchInput getInstance()
	{
		if (Integer.parseInt(Build.VERSION.SDK) <= 4)
			return SingleTouchInput.Holder.sInstance;
		else
			return MultiTouchInput.Holder.sInstance;
	}
	public abstract void process(final MotionEvent event);

	public static class SingleTouchInput extends DifferentTouchInput
	{
		private static class Holder 
		{
			private static final SingleTouchInput sInstance = new SingleTouchInput();
		}
		public void process(final MotionEvent event)
		{
			int action = -1;
			if( event.getAction() == MotionEvent.ACTION_DOWN )
				action = 0;
			if( event.getAction() == MotionEvent.ACTION_UP )
				action = 1;
			if( event.getAction() == MotionEvent.ACTION_MOVE )
				action = 2;
			if ( action >= 0 )
				DemoGLSurfaceView.nativeMouse( (int)event.getX(), (int)event.getY(), action, 0 );
		}
	}

	public static class MultiTouchInput extends DifferentTouchInput
	{
		private static class Holder 
		{
			private static final MultiTouchInput sInstance = new MultiTouchInput();
		}

		static int pointer1key=0;
		static int pointer1id=0;
		static int pointer2key=0;
		static int pointer2id=0;

		static int dpadSize = (MainActivity.screenHeight * 35) / 100;
		static int cellPad = dpadSize / 3;

		static int actionWidth  = (MainActivity.screenWidth * 12) / 100;
		static int actionHeight = (MainActivity.screenHeight * 20) / 100;

		public void process(final MotionEvent e)
		{
			boolean masked=false;
			int action=e.getAction();


			for (int i = 0; i<e.getPointerCount(); i++) {

				switch(action & MotionEvent.ACTION_MASK) {
				case MotionEvent.ACTION_POINTER_DOWN:
				case MotionEvent.ACTION_POINTER_UP:
					masked = true;
					break;
				}
				if (masked && i != ((e.getAction() & MotionEvent.ACTION_POINTER_ID_MASK) >> MotionEvent.ACTION_POINTER_ID_SHIFT
						)) { continue; }

				int type = -1;
				switch(action & MotionEvent.ACTION_MASK) {
				case MotionEvent.ACTION_DOWN: type=1; break;
				case MotionEvent.ACTION_UP: type=0; break;
				case MotionEvent.ACTION_POINTER_DOWN: type=1; break;
				case MotionEvent.ACTION_POINTER_UP: type=0; break;
				case MotionEvent.ACTION_MOVE: type=2; break;
				case MotionEvent.ACTION_OUTSIDE: type=3; break;
				case MotionEvent.ACTION_CANCEL: type=4; break;
				} 

				int id=e.getPointerId(i);
				int x=(int) e.getX(id);
				int y=(int) e.getY(id);

				int actionTopBoundary = MainActivity.screenHeight - actionHeight;
				int jumpLeftBoundary  = MainActivity.screenWidth - actionWidth;
				int runLeftBoundary   = MainActivity.screenWidth - (actionWidth * 2);

				if (x < dpadSize && y > (MainActivity.screenHeight - dpadSize) && type > 0)
				{
					int gridX = x / cellPad;
					int gridY = (y - (MainActivity.screenHeight - dpadSize)) / cellPad;

					int localKey = 0;

					if (gridX == 1 && gridY == 0) {
						localKey = 19; // UP
					} else if (gridX == 0 && gridY == 1) {
						localKey = 21; // LEFT
					} else if (gridX == 2 && gridY == 1) {
						localKey = 22; // RIGHT
					} else if (gridX == 1 && gridY == 2) {
						localKey = 20; // DOWN
					}

					if (localKey != 0)
					{
						if (pointer1key != localKey)
						{
							if (pointer1key != 0)
							{
								DemoGLSurfaceView.nativeKey(pointer1key, 0);
							}
							pointer1key = localKey;
							pointer1id = id;

							DemoGLSurfaceView.nativeKey(pointer1key, 1);
						}
					}
				}
				else if (x > jumpLeftBoundary && y > actionTopBoundary && type > 0)
				{
					if (pointer2key != 23)
					{
						if (pointer2key != 0)
						{
							DemoGLSurfaceView.nativeKey(pointer2key, 0);
						}
						pointer2key = 23;
						pointer2id = id;

						DemoGLSurfaceView.nativeKey(pointer2key, 1);
					}
				}
				else if (x > runLeftBoundary && y > actionTopBoundary && type > 0)
				{
					if (pointer2key != 82)
					{
						if (pointer2key != 0)
						{
							DemoGLSurfaceView.nativeKey(pointer2key, 0);
						}
						pointer2key = 82;
						pointer2id = id;

						DemoGLSurfaceView.nativeKey(pointer2key, 1);
					}
				}
				else
				{
					if (type==0 && pointer1key!=0 && pointer1id==id)
					{
						DemoGLSurfaceView.nativeKey( pointer1key, 0 );
						pointer1key=0;
						pointer1id=0;
					}
					else if (type==0 && pointer2key!=0 && pointer2id==id)
					{
						DemoGLSurfaceView.nativeKey( pointer2key, 0 );
						pointer2key=0;
						pointer2id=0;
					}
					else
						DemoGLSurfaceView.nativeMouse( x ,y, type, id );
				}

				if (masked) { break; }
			}
		}
	}

}

